import { existsSync, readFileSync, writeFileSync } from "node:fs";
import { resolve } from "node:path";

const TODOS_FILE = resolve(process.cwd(), "todos.json");

function readTodos(): string[] {
  if (!existsSync(TODOS_FILE)) {
    return [];
  }
  const contents = readFileSync(TODOS_FILE, "utf8");
  if (contents.trim() === "") {
    return [];
  }
  return JSON.parse(contents);
}

function writeTodos(todos: string[]): void {
  writeFileSync(TODOS_FILE, JSON.stringify(todos, null, 2));
}

function add(text: string): void {
  const todos = readTodos();
  todos.push(text);
  writeTodos(todos);
}

function list(): void {
  const todos = readTodos();
  for (const todo of todos) {
    console.log(todo);
  }
}

function main(): void {
  const [command, ...args] = process.argv.slice(2);

  if (command === "add") {
    const text = args.join(" ");
    if (text === "") {
      console.error("Usage: add <text>");
      process.exit(1);
    }
    add(text);
    return;
  }

  if (command === "list") {
    list();
    return;
  }

  console.error("Usage: cli.ts <add|list> [args]");
  process.exit(1);
}

main();

